import { type ProcessTasks } from 'wasp/server/jobs'

export const processTasks: ProcessTasks<{}, {}> = async (args, context) => {
  console.log('Processing tasks...')
  const result = await context.entities.Task.updateMany({
    where: { isProcessed: false },
    data: { isProcessed: true },
  })
  console.log(`Processed ${result.count} tasks.`)
}

