import { type CreateTask, type TriggerJob } from 'wasp/server/actions'
import { processTasks } from 'wasp/server/jobs'

export const createTask: CreateTask<{ description: string }, { id: number }> = async (args, context) => {
  return context.entities.Task.create({
    data: {
      description: args.description,
    },
  })
}

export const triggerJob: TriggerJob<{}, void> = async (args, context) => {
  await processTasks.submit({})
}

