import { useState } from 'react'
import { useQuery, getTasks, useAction, createTask, triggerJob } from 'wasp/client/operations'
import './Main.css'

export const MainPage = () => {
  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskAction = useAction(createTask)
  const triggerJobAction = useAction(triggerJob)
  const [description, setDescription] = useState('')

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!description) return
    try {
      await createTaskAction({ description })
      setDescription('')
    } catch (err: any) {
      window.alert('Error creating task: ' + err.message)
    }
  }

  const handleTriggerJob = async () => {
    try {
      await triggerJobAction({})
      window.alert('Background job triggered!')
    } catch (err: any) {
      window.alert('Error triggering job: ' + err.message)
    }
  }

  return (
    <div className="container">
      <h1>Task Processor</h1>

      <form onSubmit={handleCreateTask}>
        <input 
          type="text" 
          placeholder="Task description" 
          value={description} 
          onChange={(e) => setDescription(e.target.value)} 
        />
        <button type="submit">Add Task</button>
      </form>

      <div className="actions">
        <button onClick={handleTriggerJob} className="trigger-btn">
          Trigger Background Job
        </button>
      </div>

      {isLoading && <div>Loading tasks...</div>}
      {error && <div>Error: {error.message}</div>}

      {tasks && (
        <ul className="task-list">
          {tasks.map((task) => (
            <li key={task.id} className={task.isProcessed ? 'processed' : 'unprocessed'}>
              <span className="task-desc">{task.description}</span>
              <span className="task-status">
                {task.isProcessed ? '✅ Processed' : '⏳ Unprocessed'}
              </span>
            </li>
          ))}
        </ul>
      )}
    </div>
  )
}

