:root {
  font-family: Inter, system-ui, Avenir, Helvetica, Arial, sans-serif;
  line-height: 1.5;
  font-weight: 400;
  color-scheme: light dark;
  color: rgba(255, 255, 255, 0.87);
  background-color: #242424;
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  margin: 0;
  display: flex;
  place-items: center;
  min-width: 320px;
  min-height: 100vh;
}

#root {
  max-width: 1280px;
  margin: 0 auto;
  padding: 2rem;
  text-align: center;
}

.container {
  max-width: 600px;
  margin: 0 auto;
  padding: 2rem;
  background-color: #1a1a1a;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
}

h1 {
  font-size: 2.5em;
  line-height: 1.1;
  margin-bottom: 1.5rem;
}

form {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 2rem;
}

input {
  flex-grow: 1;
  padding: 0.6rem 1rem;
  border: 1px solid #333;
  border-radius: 4px;
  background-color: #2a2a2a;
  color: white;
}

button {
  border-radius: 8px;
  border: 1px solid transparent;
  padding: 0.6em 1.2em;
  font-size: 1em;
  font-weight: 500;
  font-family: inherit;
  background-color: #1a1a1a;
  cursor: pointer;
  transition: border-color 0.25s;
  background-color: #646cff;
  color: white;
}

button:hover {
  border-color: #646cff;
}

.actions {
  margin-bottom: 2rem;
}

.trigger-btn {
  background-color: #4caf50;
  width: 100%;
}

.trigger-btn:hover {
  border-color: #4caf50;
}

.task-list {
  list-style: none;
  padding: 0;
  text-align: left;
}

.task-list li {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.8rem;
  margin-bottom: 0.5rem;
  border-radius: 4px;
  background-color: #2a2a2a;
}

.task-list li.processed {
  border-left: 4px solid #4caf50;
}

.task-list li.unprocessed {
  border-left: 4px solid #ff9800;
}

.task-desc {
  font-weight: 500;
}

.task-status {
  font-size: 0.9em;
  opacity: 0.8;
}

