import subprocess
import os

def try_compile(wasp_content):
    with open('main.wasp', 'w') as f:
        f.write(wasp_content)
    try:
        result = subprocess.run(['wasp', 'info'], capture_output=True, text=True, timeout=30)
        if result.returncode == 0:
            return True, result.stdout
        else:
            return False, result.stderr
    except Exception as e:
        return False, str(e)

base_wasp = """app backgroundJobs {
  wasp: {
    version: "^0.21.1"
  },
  title: "background-jobs"
}

route RootRoute { path: "/", to: MainPage }
page MainPage {
  component: import { MainPage } from "@src/MainPage"
}

query getTasks {
  fn: import { getTasks } from "@src/queries",
  entities: [Task]
}

action createTask {
  fn: import { createTask } from "@src/actions",
  entities: [Task]
}

action triggerJob {
  fn: import { triggerJob } from "@src/actions",
  entities: [Task]
}
"""

variations = [
    "job processTasks { executor: Simple, perform: { fn: import { processTasks } from \"@src/jobs\" }, entities: [Task] }",
    "job processTasks { executor: SimpleExecutor, perform: { fn: import { processTasks } from \"@src/jobs\" }, entities: [Task] }",
    "job processTasks { executor: PgBoss, perform: { fn: import { processTasks } from \"@src/jobs\" }, entities: [Task] }",
]

os.chdir('/home/user/background-jobs')
for var in variations:
    print(f"Trying variation: {var}")
    success, output = try_compile(base_wasp + "\n" + var)
    if success:
        print(f"SUCCESS: {var}")
        break
    else:
        print(f"FAILED: {output[:200]}...")

db_variations = [
    "app backgroundJobs { wasp: { version: \"^0.21.1\" }, title: \"background-jobs\", db: { system: PostgreSQL } }",
