]

for var in db_variations:
    print(f"Trying DB variation: {var}")
    success, output = try_compile(var + "\n" + variations[2]) # using PgBoss
    if success:
        print(f"SUCCESS DB: {var}")
        break
    else:
        print(f"FAILED DB: {output[:200]}...")

